// Initialize the boolean array and the list
boolean[] Prime = new boolean[1001]; // 1001 is sufficient for first 100 prime numbers
ArrayList<Integer> primes = new ArrayList<>();

// Set all values in Prime[] to true
for (int i = 2; i < Prime.length; i++) {
    Prime[i] = true;
}

// Iterate from 2 to sqrt(1001)
for (int i = 2; i * i <= 1001; i++) {
    // If Prime[i] is true, then i is a prime number
    if (Prime[i]) {
        // Mark all multiples of i as not prime
        for (int j = i * i; j <= 1001; j += i) {
