const apiUrl = `https://www.googleapis.com/customsearch/v1?key=${apiKey}&cx=YOUR_SEARCH_ENGINE_ID`;

// Add event listeners
searchInput.addEventListener('input', search);
searchInput.addEventListener('keydown', search);

// Define search function
function search() {
  const term = searchInput.value.trim();
  if (term) {
    // Make API request to Google Search
    fetch(apiUrl, {
      method: 'GET',
      params: { q: term }
    })
    .then(response => response.json())
    .then(data => {
      // Display predictions
      const predictions = data.results;
      predictionsList.innerHTML = '';
      predictions.forEach(prediction => {
        const predictionElement = document.createElement('LI');
        predictionElement.textContent = prediction.title;
        predictionsList.appendChild(predictionElement);
      });
    })
